const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const norm = (s) => (s || '').replace(/\u00a0/g, ' ').replace(/\s+/g, ' ').trim();
const resolveUrl = (tile, link) => {
  // Preferred: vrhm JSON on a child div contains the real destination (murl/pgurl).
  const vrhmEl = tile.querySelector('[vrhm]');
  if (vrhmEl) {
    try {
      const meta = JSON.parse(vrhmEl.getAttribute('vrhm'));
      const cand = meta.murl || meta.pgurl;
      if (cand && /^https?:\/\//i.test(cand)) return cand;
    } catch (e) {}
  }
  const href = link ? link.getAttribute('href') : null;
  if (!href) return null;
  // Fall back to churl query param (often a channel URL, but better than the relative redirector).
  try {
    const u = new URL(href, 'https://www.bing.com');
    const churl = u.searchParams.get('churl');
    if (churl && /^https?:\/\//i.test(churl)) return churl;
    return u.href; // absolute bing.com URL
  } catch (e) {
    return href.startsWith('http') ? href : ('https://www.bing.com' + (href.startsWith('/') ? href : '/' + href));
  }
};
const tiles = Array.from(document.querySelectorAll('div.mc_vtvc')).slice(0, 20);
return tiles.map((t) => {
  const link = t.querySelector('a.mc_vtvc_link');
  const titleEl = t.querySelector('div.mc_vtvc_title');
  const title = titleEl ? norm(titleEl.textContent) : (link ? norm(link.getAttribute('aria-label') || '').split(/\s+from\s+/i)[0] : null);
  const url = resolveUrl(t, link);
  const chEl = t.querySelector('.mc_vtvc_meta_row_channel, .b_footnote');
  const channel = chEl ? norm(chEl.textContent) : null;
  return { title, url, channel };
}).filter((r) => r.title && r.url);
